sql:
SELECT AVG(average_bikes_available) AS avg_bikes_during_low_peak
FROM usage_patterns
WHERE is_low_peak = 1;

SELECT station_id, SUM(num_docks_disabled) AS total_docks_disabled
FROM station_reports
GROUP BY station_id;

SELECT num_bikes_available
FROM station_reports
WHERE report_id = 0;

external_knowledge:
- 'Current status' refers to the most recent report for each station; 
- 'Recent usage patterns' include the average availability of bikes and docks during the period of the report; 
- 'Environmental conditions' include weather, temperature, wind speed, humidity, and precipitation.

sql:
SELECT report_id, date_time, num_bikes_available
FROM station_reports
WHERE num_bikes_available > 0;

SELECT SUM(num_bikes_available) AS total_bikes_available 
FROM station_reports 
WHERE last_reported = (SELECT MAX(last_reported) FROM station_reports);

SELECT AVG(average_bikes_available) AS avg_bikes_low_peak
FROM usage_patterns
WHERE is_low_peak = 1;

SELECT report_id, num_bikes_available
FROM station_reports
WHERE num_bikes_available = (SELECT MAX(num_bikes_available) FROM station_reports);
